-- Seeds 5 realistic users for every existing organization using role ids 1, 3, 4, 7, 8.
-- Password hash for all seeded users:
-- $2a$12$QJUr6e4BD4zKcSPJ8fhsWOuyQ89yiWP544hd7I2jMY7aNZV/zP9Xi
--
-- Notes:
-- 1. This script uses deterministic usernames/emails so it can be re-run safely.
-- 2. Users are linked to the first branch available for the organization.
-- 3. State and city ids are resolved from the world reference tables when possible.
-- 4. Profile pictures are embedded directly as PNG blobs.

SET @seed_password_hash := '$2a$12$QJUr6e4BD4zKcSPJ8fhsWOuyQ89yiWP544hd7I2jMY7aNZV/zP9Xi';

SET @avatar_amy_png := X'';
SET @avatar_elwin_png := X'';
SET @avatar_bernardo_png := X'';
SET @avatar_ioni_png := X'';

DROP TEMPORARY TABLE IF EXISTS tmp_seed_role_blueprint;
CREATE TEMPORARY TABLE tmp_seed_role_blueprint (
    role_id INT NOT NULL,
    role_code VARCHAR(40) NOT NULL,
    phone_seed INT NOT NULL,
    avatar_blob LONGBLOB NOT NULL
);

INSERT INTO tmp_seed_role_blueprint (role_id, role_code, phone_seed, avatar_blob) VALUES
(1, 'opslead', 101, @avatar_amy_png),
(3, 'clinicmgr', 203, @avatar_elwin_png),
(4, 'carecoord', 304, @avatar_bernardo_png),
(7, 'frontdesk', 407, @avatar_ioni_png),
(8, 'dutydoc', 508, @avatar_amy_png);

DROP TEMPORARY TABLE IF EXISTS tmp_seed_organization_context;
CREATE TEMPORARY TABLE tmp_seed_organization_context AS
SELECT
    org_base.*,
    (
        SELECT c.id
        FROM Cities c
        WHERE c.country_id = org_base.country_id
          AND LOWER(TRIM(c.name)) COLLATE utf8mb4_unicode_ci =
              LOWER(TRIM(org_base.city_name)) COLLATE utf8mb4_unicode_ci
          AND (org_base.state_id IS NULL OR c.state_id = org_base.state_id)
        ORDER BY c.id
        LIMIT 1
    ) AS city_id
FROM (
    SELECT
        o.id AS organization_id,
        o.organization_name,
        o.country_id,
        o.state AS state_name,
        o.city AS city_name,
        o.address_line_1,
        o.address_line_2,
        o.postal_code,
        (
            SELECT b.id
            FROM Branches b
            WHERE b.organization_id = o.id
            ORDER BY b.id
            LIMIT 1
        ) AS branch_id,
        (
            SELECT s.id
            FROM States s
            WHERE s.country_id = o.country_id
              AND LOWER(TRIM(s.name)) COLLATE utf8mb4_unicode_ci =
                  LOWER(TRIM(o.state)) COLLATE utf8mb4_unicode_ci
            ORDER BY s.id
            LIMIT 1
        ) AS state_id
    FROM Organizations o
) org_base;

INSERT INTO UserDetails (
    user_name,
    password,
    email_id,
    user_type,
    contact,
    role_id,
    organization_id,
    branch_id,
    country_id,
    state_id,
    city_id,
    address,
    access_right_id,
    status_id,
    last_password_change,
    last_successful_login,
    last_seen_at,
    last_logout_at,
    last_session_id,
    profile_image,
    profile_image_content_type,
    created_at,
    updated_at
)
SELECT
    seed.user_name,
    @seed_password_hash,
    seed.email_id,
    'GENERAL_USER',
    seed.contact_number,
    seed.role_id,
    seed.organization_id,
    seed.branch_id,
    seed.country_id,
    seed.state_id,
    seed.city_id,
    seed.full_address,
    1,
    3,
    CURRENT_TIMESTAMP,
    NULL,
    NULL,
    NULL,
    NULL,
    seed.avatar_blob,
    'image/png',
    CURRENT_TIMESTAMP,
    CURRENT_TIMESTAMP
FROM (
    SELECT
        seeded_row.organization_id,
        seeded_row.branch_id,
        seeded_row.country_id,
        seeded_row.state_id,
        seeded_row.city_id,
        seeded_row.role_id,
        seeded_row.avatar_blob,
        seeded_row.first_name,
        seeded_row.last_name,
        LOWER(
            CONCAT(
                REPLACE(seeded_row.first_name, ' ', ''),
                '.',
                REPLACE(seeded_row.last_name, ' ', ''),
                '.',
                LPAD(seeded_row.organization_id, 4, '0'),
                '.',
                seeded_row.role_code
            )
        ) AS user_name,
        LOWER(
            CONCAT(
                REPLACE(seeded_row.first_name, ' ', ''),
                '.',
                REPLACE(seeded_row.last_name, ' ', ''),
                '.',
                LPAD(seeded_row.organization_id, 4, '0'),
                '.',
                seeded_row.role_code,
                '@carexusers.in'
            )
        ) AS email_id,
        CONCAT(
            '9',
            LPAD((((seeded_row.organization_id * 97) + seeded_row.phone_seed) MOD 999999999), 9, '0')
        ) AS contact_number,
        CONCAT_WS(
            ', ',
            NULLIF(seeded_row.address_line_1, ''),
            NULLIF(seeded_row.address_line_2, ''),
            NULLIF(seeded_row.city_name, ''),
            NULLIF(seeded_row.state_name, ''),
            NULLIF(seeded_row.postal_code, '')
        ) AS full_address
    FROM (
        SELECT
            oc.organization_id,
            oc.branch_id,
            oc.country_id,
            oc.state_id,
            oc.city_id,
            oc.address_line_1,
            oc.address_line_2,
            oc.state_name,
            oc.city_name,
            oc.postal_code,
            rb.role_id,
            rb.role_code,
            rb.phone_seed,
            rb.avatar_blob,
            CASE rb.role_id
                WHEN 1 THEN ELT(((oc.organization_id + 1) MOD 12) + 1, 'Aarav', 'Nithya', 'Karthik', 'Priya', 'Vikram', 'Meera', 'Rohit', 'Ananya', 'Sanjay', 'Kavya', 'Ritesh', 'Deepa')
                WHEN 3 THEN ELT(((oc.organization_id + 3) MOD 12) + 1, 'Harini', 'Arjun', 'Naveen', 'Ishita', 'Pranav', 'Divya', 'Aditya', 'Shruti', 'Gokul', 'Ritika', 'Sudeep', 'Lakshmi')
                WHEN 4 THEN ELT(((oc.organization_id + 5) MOD 12) + 1, 'Manoj', 'Asha', 'Vignesh', 'Rekha', 'Tarun', 'Bhavya', 'Jatin', 'Neha', 'Mohan', 'Sneha', 'Aravind', 'Pallavi')
                WHEN 7 THEN ELT(((oc.organization_id + 7) MOD 12) + 1, 'Pooja', 'Nisha', 'Keerthana', 'Sahana', 'Varsha', 'Farah', 'Aparna', 'Nandini', 'Mitali', 'Swathi', 'Rhea', 'Madhavi')
                WHEN 8 THEN ELT(((oc.organization_id + 9) MOD 12) + 1, 'Rahul', 'Siddharth', 'Abhinav', 'Naveena', 'Kiran', 'Aditi', 'Surya', 'Ashwin', 'Tanvi', 'Mitesh', 'Vasudha', 'Anirudh')
            END AS first_name,
            CASE rb.role_id
                WHEN 1 THEN ELT(((oc.organization_id * 3 + 1) MOD 12) + 1, 'Rao', 'Iyer', 'Menon', 'Khanna', 'Reddy', 'Shah', 'Sinha', 'Nair', 'Bhat', 'Kulkarni', 'Verma', 'Chawla')
                WHEN 3 THEN ELT(((oc.organization_id * 3 + 3) MOD 12) + 1, 'Narayanan', 'Patel', 'Arora', 'Joshi', 'Nambiar', 'Kapoor', 'Saxena', 'Subramanian', 'Mishra', 'Desai', 'Agarwal', 'Thomas')
                WHEN 4 THEN ELT(((oc.organization_id * 3 + 5) MOD 12) + 1, 'Gowda', 'Fernandes', 'Krishnan', 'Malhotra', 'Bose', 'Tiwari', 'Mukherjee', 'Bedi', 'Yadav', 'Pai', 'Shetty', 'Balan')
                WHEN 7 THEN ELT(((oc.organization_id * 3 + 7) MOD 12) + 1, 'Raman', 'Dutta', 'George', 'Gill', 'Naidu', 'Chatterjee', 'Pillai', 'Jain', 'Kohli', 'Basu', 'Prasad', 'Mathew')
                WHEN 8 THEN ELT(((oc.organization_id * 3 + 9) MOD 12) + 1, 'Srinivasan', 'Banerjee', 'Kumar', 'Mahajan', 'Parikh', 'Bhardwaj', 'Sethi', 'Rajan', 'Pinto', 'Wadhwa', 'Anand', 'Chopra')
            END AS last_name
        FROM tmp_seed_organization_context oc
        CROSS JOIN tmp_seed_role_blueprint rb
    ) seeded_row
) seed
WHERE NOT EXISTS (
    SELECT 1
    FROM UserDetails ud
    WHERE ud.email_id = seed.email_id
);

DROP TEMPORARY TABLE IF EXISTS tmp_seed_role_blueprint;
DROP TEMPORARY TABLE IF EXISTS tmp_seed_organization_context;

SELECT
    COUNT(*) AS seeded_user_count
FROM UserDetails
WHERE email_id LIKE '%@carexusers.in';

SELECT
    organization_id,
    COUNT(*) AS seeded_users_for_organization
FROM UserDetails
WHERE email_id LIKE '%@carexusers.in'
GROUP BY organization_id
ORDER BY organization_id;
